#include <stdio.h>

struct Player {
    int health;
};

// Expect a pointer to a Player struct
void heal(struct Player *p) {
    // We MUST use -> because p is a pointer, not the real thing
    p->health = 100;
}

int main() {
    struct Player hero = {10};

    heal(&hero); // Pass the address map!

    printf("Hero HP is now %d\n", hero.health);
    return 0;
}
